import{_ as e,o as s,c as i,a2 as n}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"MVCC y aislamiento","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/postgresql/12-mvcc-y-aislamiento.md","filePath":"bases-de-datos/postgresql/12-mvcc-y-aislamiento.md","lastUpdated":1782521464000}'),t={name:"bases-de-datos/postgresql/12-mvcc-y-aislamiento.md"};function l(o,a,r,c,d,p){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="mvcc-y-aislamiento" tabindex="-1">MVCC y aislamiento <a class="header-anchor" href="#mvcc-y-aislamiento" aria-label="Permalink to &quot;MVCC y aislamiento&quot;">​</a></h1><p>MVCC significa Multi-Version Concurrency Control. PostgreSQL permite que lectores y escritores trabajen a la vez manteniendo varias versiones de una fila.</p><h2 id="idea-central" tabindex="-1">Idea central <a class="header-anchor" href="#idea-central" aria-label="Permalink to &quot;Idea central&quot;">​</a></h2><p>Cuando una transaccion actualiza una fila, PostgreSQL no sobrescribe directamente la version visible. Crea una nueva version y marca metadatos de visibilidad.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[&quot;fila version 1&quot;] --&gt; B[&quot;UPDATE&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[&quot;fila version 2&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A --&gt; D[&quot;visible para transacciones antiguas&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; E[&quot;visible para transacciones nuevas&quot;]</span></span></code></pre></div><h2 id="xmin-y-xmax" tabindex="-1">xmin y xmax <a class="header-anchor" href="#xmin-y-xmax" aria-label="Permalink to &quot;xmin y xmax&quot;">​</a></h2><p>Cada fila tiene metadatos internos:</p><ul><li><code>xmin</code>: transaccion que creo la version.</li><li><code>xmax</code>: transaccion que invalido o borro la version.</li></ul><p>La visibilidad depende del snapshot de la transaccion que consulta.</p><h2 id="snapshots" tabindex="-1">Snapshots <a class="header-anchor" href="#snapshots" aria-label="Permalink to &quot;Snapshots&quot;">​</a></h2><p>Un snapshot define que transacciones eran visibles en un momento.</p><p>Por eso una consulta puede no ver cambios confirmados despues de iniciar una transaccion, segun el nivel de aislamiento.</p><h2 id="niveles-de-aislamiento" tabindex="-1">Niveles de aislamiento <a class="header-anchor" href="#niveles-de-aislamiento" aria-label="Permalink to &quot;Niveles de aislamiento&quot;">​</a></h2><ul><li><code>READ COMMITTED</code>: cada sentencia ve un snapshot nuevo.</li><li><code>REPEATABLE READ</code>: toda la transaccion mantiene snapshot estable.</li><li><code>SERIALIZABLE</code>: simula ejecucion serial y puede requerir reintentos.</li></ul><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BEGIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ISOLATION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LEVEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> REPEATABLE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> READ</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> cuentas </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COMMIT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="lectores-no-bloquean-escritores" tabindex="-1">Lectores no bloquean escritores <a class="header-anchor" href="#lectores-no-bloquean-escritores" aria-label="Permalink to &quot;Lectores no bloquean escritores&quot;">​</a></h2><p>Una de las ventajas de MVCC es que una lectura normal no bloquea una escritura normal, y una escritura no bloquea lecturas normales.</p><p>Pero si quedan versiones antiguas, hace falta vacuum para limpiar.</p><h2 id="problemas-que-evita-y-problemas-que-no-evita" tabindex="-1">Problemas que evita y problemas que no evita <a class="header-anchor" href="#problemas-que-evita-y-problemas-que-no-evita" aria-label="Permalink to &quot;Problemas que evita y problemas que no evita&quot;">​</a></h2><p>MVCC ayuda con:</p><ul><li>Lecturas consistentes.</li><li>Menos bloqueos entre lectura y escritura.</li><li>Concurrencia alta.</li></ul><p>No elimina:</p><ul><li>Deadlocks.</li><li>Conflictos de escritura.</li><li>Bloat.</li><li>Necesidad de indices.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Manten transacciones cortas.</li><li>Evita sesiones <code>idle in transaction</code>.</li><li>Usa <code>SERIALIZABLE</code> solo cuando lo necesites.</li><li>Prepara reintentos para conflictos.</li><li>Monitoriza bloat y autovacuum.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Dejar una transaccion abierta durante minutos.</li><li>Pensar que MVCC evita todos los bloqueos.</li><li>No entender por que una tabla crece tras muchos updates.</li><li>No reintentar transacciones serializables fallidas.</li></ul>`,27)])])}const m=e(t,[["render",l]]);export{h as __pageData,m as default};
